import React, { useState, useEffect } from "react";
import { Field, Form, useField } from "react-final-form";
import arrayMutators from "final-form-arrays";
import { FieldArray } from "react-final-form-arrays";
import { InputField } from "../../../common/InputText";
import { Error, PageMode, required } from "../../../common/Utilitis";
import FacilityService from "../../services/facilities.service";
import TreatmentService from "../../services/treatments.service";
import CountryService from "../../services/countries.service";
import CityService from "../../services/cities.service";
import { useTranslation } from "react-i18next";
import Select from "react-select";
function AddUpdateForm(props) {
  const [t] = useTranslation();
  const { mode, selectedTreatment, onClose } = props;
  const [isLoading, setIsLoading] = useState(false);
  const [isCityLoading, setIsCityLoading] = useState(false);
  const [message, setMessage] = useState();
  const [facilitiesData, setFacilitiesData] = useState([]);
  const [countriesData, setCountriesData] = useState([]);
  const [citiesData, setCitiesData] = useState([]);
  useEffect(async () => {
    setIsCityLoading(true);
    const facilityServiceResponse = await FacilityService.getAllFacilities();
    const countryResponse = await CountryService.getAllCountries();
    const cityResponse = await CityService.getAllCities();
    setMessage(
      !!facilityServiceResponse?.message && facilityServiceResponse?.message
    );
    if (facilityServiceResponse.success) {
      setFacilitiesData(facilityServiceResponse.body);
    }
    if (countryResponse.success) {
      setCountriesData(countryResponse.body);
    }
    if (cityResponse.success) {
      setCitiesData(cityResponse.body);
    }
    setIsCityLoading(false);
  }, []);

  const onSubmit = async (values) => {
    let treatmentData = {
      name: values.name,
      facilities: values.facilities?.map((f) => f.facility.value),
    };
    setIsLoading(true);
    let response;
    if (mode === PageMode.Update) {
      response = await TreatmentService.updateTreatment(
        selectedTreatment?.id,
        treatmentData
      );
    } else {
      response = await TreatmentService.createTreatment(treatmentData);
    }
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    onClose(response.body);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.name) {
      errors.name = required;
    }
    return errors;
  };
  const SelectAdapter = ({ input, ...rest }) => (
    <Select {...input} {...rest} searchable />
  );
  const countriesOptions = isCityLoading
    ? [{ value: "", label: t("loading") }]
    : countriesData?.map((val) => ({ value: val.id, label: val.name }));

  const CitiesOptions = ({ countries, cities, citiesData, children }) => {
    const countryField = useField(countries, { subscription: { value: 1 } });
    const cityField = useField(cities, { subscription: {} });
    const countryValue = countryField.input.value.value;
    const changeCity = cityField.input.onChange;
    const [options, setOptions] = React.useState([]);

    React.useEffect(() => {
      changeCity(undefined); // clear B
      setOptions(
        citiesData
          ?.filter((c) => c.country?.id === countryValue)
          ?.map((val) => ({ value: val.id, label: val.name }))
      );
    }, [countryValue, changeCity]);
    return children(options || []);
  };

  const FacilitiesOptions = ({
    cities,
    facilities,
    facilitirsData,
    children,
  }) => {
    const cityField = useField(cities, { subscription: { value: 1 } });
    const facilityField = useField(facilities, { subscription: {} });
    const cityValue = cityField.input.value.value;
    const changeFacility = facilityField.input.onChange;
    const [options, setOptions] = React.useState([]);

    React.useEffect(() => {
      changeFacility(undefined); // clear B
      setOptions(
        facilitirsData
          ?.filter((c) => c.city?.id === cityValue)
          ?.map((val) => ({ value: val.id, label: val.name }))
      );
    }, [cityValue, changeFacility]);
    return children(options || []);
  };

  const requiredArray = (value) =>
    value && value.length > 0 ? undefined : required;
  const selectRequired = (value) => (value ? undefined : required);

  let selectedFacilities = selectedTreatment?.facilities.map((f) => ({
    facility: {
      value: f.id,
      label: f.name,
    },
    country: {
      value: f.city.country.id,
      label: f.city.country.name,
    },
    city: {
      value: f.city.id,
      label: f.city.name,
    },
  }));
  return (
    <div>
      <Form
        initialValues={{
          name: selectedTreatment?.name,
        }}
        validate={validate}
        onSubmit={onSubmit}
        mutators={{
          ...arrayMutators,
        }}
        render={({
          handleSubmit,
          onChange,
          submitError,
          form: {
            mutators: { push, pop },
          },
          form,
          submitting,
          pristine,
          values,
        }) => {
          return (
            <form
              onSubmit={handleSubmit}
              className="needs-validation"
              noValidate
            >
              {message && (
                <div className="invalid-feedback d-block mb-2">{message}</div>
              )}
              <div>
                <div className="row form-row">
                  <div className="col-12 col-md-12">
                    <div className="form-group">
                      <label>{t("Treatment.Name")}</label>
                      <Field
                        name="name"
                        className="form-control floating"
                        type="text"
                        component={InputField}
                      />
                    </div>
                  </div>
                  <div className="col-12 col-md-6">
                    <div className="form-group">
                      <button
                        className="btn btn-secondary submit-btn"
                        type="button"
                        style={{ marginTop: "34px" }}
                        onClick={() => push("facilities", undefined)}
                      >
                        Add facility
                      </button>
                    </div>
                  </div>
                </div>
                <FieldArray
                  initialValue={selectedFacilities}
                  name="facilities"
                  validate={requiredArray}
                  showerrorbeside="true"
                >
                  {({ fields }) =>
                    fields.map((name, index) => (
                      <div key={name}>
                        <div className="row form-row">
                          <div className="col-12 col-md-4">
                            <div className="form-group">
                              <label>{t("Treatment.Country")}</label>
                              <Field
                                name={`${name}.country`}
                                component={SelectAdapter}
                                options={countriesOptions}
                                validate={selectRequired}
                              />
                              <Error
                                name={`${name}.country`}
                                showerrorbeside="true"
                              />
                            </div>
                          </div>
                          <div className="col-12 col-md-4">
                            <div className="form-group">
                              <label>{t("Treatment.City")}</label>
                              <CitiesOptions
                                countries={`${name}.country`}
                                cities={`${name}.city`}
                                citiesData={citiesData}
                              >
                                {(options) => (
                                  <Field
                                    name={`${name}.city`}
                                    component={SelectAdapter}
                                    options={options}
                                    validate={selectRequired}
                                    defaultValue={1}
                                    value={1}
                                    initialValue={
                                      selectedFacilities &&
                                      selectedFacilities[index] &&
                                      selectedFacilities[index].city &&
                                      options?.filter(
                                        (option) =>
                                          option.value ==
                                          selectedFacilities[index].city.value
                                      )[0]
                                    }
                                  />
                                )}
                              </CitiesOptions>
                              <Error
                                name={`${name}.city`}
                                showerrorbeside="true"
                              />
                            </div>
                          </div>
                          <div className="col-12 col-md-3">
                            <div className="form-group">
                              <label>{t("Treatment.Facility")}</label>
                              <FacilitiesOptions
                                cities={`${name}.city`}
                                facilities={`${name}.facility`}
                                facilitirsData={facilitiesData}
                              >
                                {(options) => (
                                  <Field
                                    name={`${name}.facility`}
                                    component={SelectAdapter}
                                    options={options}
                                    validate={selectRequired}
                                    initialValue={
                                      selectedFacilities &&
                                      selectedFacilities[index] && 
                                      selectedFacilities[index].facility &&
                                      options?.filter(
                                        (option) =>
                                          option.value ==
                                          selectedFacilities[index].facility
                                            .value
                                      )[0]
                                    }
                                  />
                                )}
                              </FacilitiesOptions>
                              <Error
                                name={`${name}.facility`}
                                showerrorbeside="true"
                              />
                            </div>
                          </div>

                          <span
                            onClick={() => fields.remove(index)}
                            style={{ cursor: "pointer", marginTop: "44px" }}
                          >
                            ❌
                          </span>
                        </div>
                      </div>
                    ))
                  }
                </FieldArray>
              </div>
              <div className="submit-section">
                <button
                  type="submit"
                  className="btn btn-primary submit-btn"
                  disabled={isLoading}
                >
                  {!isLoading ? t(`Treatment.Save`) : ""}
                  {isLoading && (
                    <span className="spinner-border spinner-border-sm mb-1"></span>
                  )}
                </button>
                <button
                  className="btn btn-secondary submit-btn"
                  onClick={(e) => {
                    e.preventDefault();
                    onClose(null);
                  }}
                >
                  {t("Treatment.Close")}
                </button>
              </div>
            </form>
          );
        }}
      />
    </div>
  );
}

export default AddUpdateForm;
