import Alert from "@mui/material/Alert";
import CircularProgress from "@mui/material/CircularProgress";
import { useEffect, useState } from "react";
import { Modal } from "react-bootstrap";
import StickyBox from "react-sticky-box";
import DashboardSidebar from "../../../client/components/dashboard/sidebar/sidebar.jsx";
import DataTable from "../../../common/DataTable";
import { PageMode } from "../../../common/Utilitis";
import TreatmentService from "../../services/treatments.service";
import AddUpdateForm from "./AddUpdateForm";
import { useTranslation } from "react-i18next";
function TreatmentsList() {
  const [t] = useTranslation();
  const [loading, setLoading] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [show, setShow] = useState(false);
  const [showDelete, setShowDelete] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [message, setMessage] = useState();
  const [messageDelete, setMessageDelete] = useState();
  const [treatmentsData, setTreatmentsData] = useState();
  const [selectedTreatment, setSelectedTreatment] = useState(null);
  const [mode, setMode] = useState(PageMode.Add);
  const handleClose = () => setShow(false);
  const handleShow = () => {
    setShow(true);
    setShowSuccess(false);
  };
  const handleCloseDelete = () => setShowDelete(false);
  const handleShowDelete = () => {
    setShowDelete(true);
    setShowSuccess(false);
  };

  useEffect(async () => {
    setLoading(true);
    const response = await TreatmentService.getAllTreatments();
    setMessage(!!response?.message && response?.message);
    if (response.success) {
      setTreatmentsData(response.body);
    }

    setLoading(false);
  }, []);

  const deleteTreatmentHandler = async (id) => {
    setDeleting(true);

    const response = await TreatmentService.deleteTreatment(id);

    setDeleting(false);
    if (!!!response.success && !response.success) {
      setMessageDelete(!!response.message && response.message);
      return;
    }
    handleCloseDelete();
    setTreatmentsData(treatmentsData.filter((u) => u.id != id));

    if (!!!response.success && !response.success) {
      setMessage(!!response?.message && response?.message);
      // To-Do: implemet error msg
      setLoading(false);
      return;
    }
    setLoading(false);
  };

  const columns = [{ id: "name", label: t("Treatment.Name") }];
  let tableContent = (
    <DataTable
      columns={columns}
      rows={treatmentsData?.flat()}
      showActions={true}
      onEdit={(treatment) => {
        handleShow();
        setSelectedTreatment(treatment);
        setMode(PageMode.Update);
      }}
      onDelete={(treatment) => {
        handleShowDelete();
        setSelectedTreatment(treatment);
        setMessageDelete(null);
      }}
    />
  );

  return (
    <div>
      <div className="content">
        <div className="container-fluid">
          <div className="row">
            <div className="col-md-5 col-lg-4 col-xl-3 theiaStickySidebar">
              <StickyBox offsetTop={20} offsetBottom={20}>
                <DashboardSidebar />
              </StickyBox>
            </div>
            <div className="col-md-7 col-lg-8 col-xl-9">
              <div className="row">
                <div className="col-sm-12">
                  <div className="card">
                    <div className="card-header">
                      <h4 className="card-title float-left">
                        {t("Treatment.ListTitle")}
                      </h4>
                      <button
                        className="btn btn-primary float-right"
                        onClick={() => {
                          handleShow();
                          setSelectedTreatment(null);
                          setMode(PageMode.Add);
                        }}
                        data-toggle="modal"
                      >
                        {t("Treatment.Add")}
                      </button>
                    </div>
                    <div className="card-body ">
                      <div className="card card-table mb-0">
                        <div className="card-body">
                          <div className="table-responsive">
                            <div className="invalid-feedback d-block mb-2">
                              {message}
                            </div>
                            {loading ? (
                              <div className="centered">
                                <h4>
                                  <div>
                                    <CircularProgress />
                                  </div>
                                  <div>
                                    <span style={{ color: "#15558d" }}>
                                      {t("Treatment.GettingTreatments")}
                                    </span>
                                  </div>
                                </h4>
                              </div>
                            ) : (
                              <>
                                {showSuccess ? (
                                  <div style={{ margin: "20px" }}>
                                    <Alert severity="success">
                                      {mode === PageMode.Add
                                        ? t(
                                            "Treatment.AddingSuccessfullyMessage"
                                          )
                                        : t(
                                            "Treatment.UpdatingSuccessfullyMessage"
                                          )}
                                    </Alert>
                                  </div>
                                ) : (
                                  <></>
                                )}
                                {tableContent}
                              </>
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <Modal
        show={show}
        onHide={handleClose}
        size="lg"
        scrollable={false}
        aria-labelledby="example-modal-sizes-title-sm"
      >
        <Modal.Header>
          <h5 className="modal-title">{`${t(mode)} ${t(
            "Treatment.Treatment"
          )}`}</h5>
          <button
            type="button"
            className="close"
            data-dismiss="modal"
            aria-label="Close"
            onClick={handleClose}
          >
            <span aria-hidden="true">×</span>
          </button>
        </Modal.Header>
        <Modal.Body>
          <div className="modal-body">
            <div>
              <AddUpdateForm
                selectedTreatment={selectedTreatment}
                mode={mode}
                onClose={(treatment) => {
                  handleClose();
                  if (treatment) {
                    if (mode === PageMode.Update) {
                      const updatedTreatment = treatmentsData
                        .flat()
                        .map((u) => {
                          return u.id === treatment.id
                            ? {
                                ...treatment,
                              }
                            : u;
                        });
                      setTreatmentsData(updatedTreatment);
                    } else {
                      const addedTreatment = {
                        ...treatment,
                      };
                      setTreatmentsData([...treatmentsData, addedTreatment]);
                    }
                    setShowSuccess(true);
                  }
                }}
              />
            </div>
          </div>
        </Modal.Body>
      </Modal>

      <Modal
        show={showDelete}
        onHide={handleCloseDelete}
        aria-labelledby="example-modal-sizes-title-sm"
        centered
      >
        <Modal.Header>
          <h5 className="modal-title">
            {t("Treatment.DeleteConfirmationTitle")}
          </h5>
          <button
            type="button"
            className="close"
            data-dismiss="modal"
            aria-label="Close"
            onClick={handleCloseDelete}
          >
            <span aria-hidden="true">×</span>
          </button>
        </Modal.Header>
        <Modal.Body>
          <div className="modal-body">
            {messageDelete && (
              <div className="invalid-feedback d-block mb-2">
                {messageDelete}
              </div>
            )}
            <h5 style={{ color: "red" }}>
              {t("Treatment.DeleteConfirmationMessage")}
            </h5>
            <div>
              <b>{t("Treatment.Treatment")}:</b>
              {` ${selectedTreatment?.name} `}
            </div>
          </div>
        </Modal.Body>
        <Modal.Footer>
          <button
            className="btn btn-danger submit-btn"
            disabled={deleting}
            onClick={() => {
              deleteTreatmentHandler(selectedTreatment.id);
            }}
          >
            {!deleting ? t(`Treatment.Delete`) : ""}
            {deleting && (
              <span className="spinner-border spinner-border-sm mb-1"></span>
            )}
          </button>
          <button
            className="btn btn-secondary submit-btn"
            onClick={handleCloseDelete}
          >
            {t("Treatment.Close")}
          </button>
        </Modal.Footer>
      </Modal>
    </div>
  );
}
export default TreatmentsList;
